const input = $json.body ?? $json;
const requestId = String(input.request_id ?? '').trim();

const valid =
  /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i
    .test(requestId);

return [{
  json: {
    ok: valid,
    request_id: requestId,
    error: valid
      ? null
      : {
          code: 'INVALID_REQUEST_ID',
          message: 'request_id غير صالح.'
        }
  }
}];

const payload = $json;

let request = null;
if (Array.isArray(payload)) request = payload[0] ?? null;
else if (Array.isArray(payload?.data)) request = payload.data[0] ?? null;
else if (payload?.id) request = payload;

if (!request) {
  return [{
    json: {
      ok: false,
      http_status: 404,
      error: {
        code: 'REQUEST_NOT_FOUND',
        message: 'طلب الحملة غير موجود.'
      }
    }
  }];
}

const blockedStatuses = [
  'building',
  'ready_for_review',
  'approved',
  'published'
];

if (blockedStatuses.includes(request.status)) {
  return [{
    json: {
      ok: false,
      duplicate: true,
      http_status: 200,
      request,
      error: {
        code: 'BUILD_ALREADY_STARTED',
        message: 'تم بدء بناء هذه الحملة أو إنشاؤها مسبقًا.'
      }
    }
  }];
}

if (request.status !== 'strategy_ready') {
  return [{
    json: {
      ok: false,
      http_status: 409,
      request,
      error: {
        code: 'REQUEST_NOT_READY',
        message: `حالة الطلب ${request.status} وليست strategy_ready.`
      }
    }
  }];
}

const requestPayload = request.request_payload ?? {};
const safety = requestPayload.safety_review ?? {};

if (safety.approved !== true || safety.final_strategy?.safe_to_build === false) {
  return [{
    json: {
      ok: false,
      http_status: 422,
      request,
      error: {
        code: 'SAFETY_REVIEW_NOT_APPROVED',
        message: 'مراجعة الأمان لم تسمح ببناء الحملة تلقائيًا.'
      }
    }
  }];
}

const strategies = Array.isArray(request.campaign_strategies)
  ? request.campaign_strategies
  : [];

const selected =
  strategies.find((strategy) => strategy.selected === true) ??
  strategies.find(
    (strategy) =>
      strategy.tier === requestPayload.selected_strategy_tier
  );

if (!selected) {
  return [{
    json: {
      ok: false,
      http_status: 404,
      request,
      error: {
        code: 'SELECTED_STRATEGY_NOT_FOUND',
        message: 'لم يتم العثور على الاستراتيجية التي اختارها الذكاء الاصطناعي.'
      }
    }
  }];
}

const budget = Number(selected.daily_budget);
if (!Number.isFinite(budget) || budget < 5 || budget > 25) {
  return [{
    json: {
      ok: false,
      http_status: 422,
      request,
      error: {
        code: 'INVALID_DAILY_BUDGET',
        message: 'ميزانية الاستراتيجية خارج الحد المسموح 5-25 دولارًا.'
      }
    }
  }];
}

const executionMode = String(
  request.execution_mode ?? 'dry_run'
).toLowerCase();

if (!['dry_run', 'review', 'live'].includes(executionMode)) {
  return [{
    json: {
      ok: false,
      http_status: 422,
      request,
      error: {
        code: 'INVALID_EXECUTION_MODE',
        message: 'وضع التنفيذ غير مدعوم.'
      }
    }
  }];
}

const contentLibraryId =
  requestPayload.content_library_id ?? null;

return [{
  json: {
    ok: true,
    http_status: 200,
    request,
    strategy: selected,
    execution_mode: executionMode,
    final_meta_status:
      executionMode === 'live'
        ? 'ACTIVE'
        : 'PAUSED',
    content_library_id: contentLibraryId,
    credential_group:
      request.target_meta_account_id === 'act_1264530092507896'
        ? 'B'
        : 'A',
    page_id:
      requestPayload.page_id ??
      '1196152526914949',
    instagram_user_id:
      requestPayload.instagram_user_id ??
      '17841448275535851',
    whatsapp_phone_number:
      requestPayload.whatsapp_phone_number ??
      null,
    resolved: {
      object_story_id:
        requestPayload.object_story_id ?? null,
      instagram_media_id:
        requestPayload.instagram_media_id ?? null
    }
  }
}];

const ctx = $('Select Autonomous Strategy').first().json;
const payload = $json;

let rows = [];
if (Array.isArray(payload)) rows = payload;
else if (Array.isArray(payload?.data)) rows = payload.data;

const duplicate = rows[0] ?? null;

return [{
  json: {
    ...ctx,
    ok: !duplicate,
    duplicate_campaign_request: duplicate,
    error: duplicate
      ? {
          code: 'CONTENT_ALREADY_PROMOTED',
          message: 'هذا المنشور لديه حملة قائمة أو تم بناؤها بالفعل.'
        }
      : null
  }
}];

const ctx = $('Select Autonomous Strategy').first().json;
const now = new Date().toISOString();

return [{
  json: {
    request_id: ctx.request.id,
    strategy_id: ctx.strategy.id,
    execution_mode: ctx.execution_mode,
    patch: {
      status: 'building',
      error_code: null,
      error_message: null,
      request_payload: {
        ...(ctx.request.request_payload ?? {}),
        auto_execution: true,
        build_started_at: now,
        build_progress: {
          stage: 'accepted',
          updated_at: now
        },
        selected_strategy_tier: ctx.strategy.tier
      }
    }
  }
}];

const ctx = $('Select Autonomous Strategy').first().json;

return [{
  json: {
    ok: true,
    accepted: true,
    request_id: ctx.request.id,
    strategy_id: ctx.strategy.id,
    selected_tier: ctx.strategy.tier,
    execution_mode: ctx.execution_mode,
    status: 'building',
    message: 'تم قبول بناء الحملة وبدأ التنفيذ التلقائي في الخلفية.'
  }
}];

const ctx = $('Select Autonomous Strategy').first().json;
const now = new Date().toISOString();

return [{
  json: {
    request_id: ctx.request.id,
    strategy_id: ctx.strategy.id,
    request_patch: {
      status: 'strategy_ready',
      error_code: null,
      error_message: null,
      request_payload: {
        ...(ctx.request.request_payload ?? {}),
        dry_run_completed_at: now,
        build_progress: {
          stage: 'dry_run_completed',
          updated_at: now
        }
      }
    },
    strategy_patch: {
      status: 'selected',
      selected: true,
      build_error_code: null,
      build_error_message: null
    }
  }
}];

const ctx = $('Select Autonomous Strategy').first().json;
const strategy = ctx.strategy;
const request = ctx.request;

const cents = Math.round(Number(strategy.daily_budget) * 100);

const targeting = {
  geo_locations: {
    countries:
      Array.isArray(strategy.country_codes) &&
      strategy.country_codes.length
        ? strategy.country_codes
        : ['PS']
  },
  age_min: Number(strategy.age_min),
  age_max: Number(strategy.age_max)
};

if (strategy.gender === 'female') targeting.genders = [1];
if (strategy.gender === 'male') targeting.genders = [2];

const placements = Array.isArray(strategy.placements)
  ? strategy.placements
  : [];

const publisherPlatforms = [];
if (placements.some((value) => value.startsWith('facebook_'))) {
  publisherPlatforms.push('facebook');
}
if (placements.some((value) => value.startsWith('instagram_'))) {
  publisherPlatforms.push('instagram');
}

if (publisherPlatforms.length) {
  targeting.publisher_platforms = publisherPlatforms;
}

const facebookPositions = [];
const instagramPositions = [];

for (const placement of placements) {
  if (placement === 'facebook_feed') facebookPositions.push('feed');
  if (placement === 'facebook_reels') facebookPositions.push('facebook_reels');
  if (placement === 'facebook_stories') facebookPositions.push('story');
  if (placement === 'instagram_feed') instagramPositions.push('stream');
  if (placement === 'instagram_reels') instagramPositions.push('reels');
  if (placement === 'instagram_stories') instagramPositions.push('story');
}

if (facebookPositions.length) {
  targeting.facebook_positions = [...new Set(facebookPositions)];
}
if (instagramPositions.length) {
  targeting.instagram_positions = [...new Set(instagramPositions)];
}

const finalStatus = ctx.final_meta_status;

const campaignPayload = {
  name: strategy.campaign_name,
  objective: strategy.objective,
  status: finalStatus,
  special_ad_categories: [],
  is_adset_budget_sharing_enabled: false
};

const adsetPayload = {
  name: `${strategy.campaign_name} | ${strategy.tier}`,
  campaign_id: null,
  daily_budget: cents,
  billing_event: strategy.billing_event || 'IMPRESSIONS',
  optimization_goal: strategy.optimization_goal,
  bid_strategy: strategy.bid_strategy || 'LOWEST_COST_WITHOUT_CAP',
  status: finalStatus,
  targeting
};

const destination = String(strategy.destination_type).toUpperCase();

if (destination === 'WHATSAPP') {
  if (!ctx.whatsapp_phone_number) {
    throw new Error(
      'WHATSAPP_PHONE_NUMBER_MISSING: request_payload.whatsapp_phone_number is required.'
    );
  }

  adsetPayload.destination_type = 'WHATSAPP';
  adsetPayload.promoted_object = {
    page_id: ctx.page_id,
    whatsapp_phone_number: ctx.whatsapp_phone_number
  };
} else if (destination === 'MESSENGER') {
  adsetPayload.destination_type = 'MESSENGER';
  adsetPayload.promoted_object = {
    page_id: ctx.page_id
  };
} else if (destination === 'WEBSITE') {
  adsetPayload.destination_type = 'WEBSITE';
}

return [{
  json: {
    ...ctx,
    campaign_payload: campaignPayload,
    adset_payload: adsetPayload
  }
}];

if (!$json.id) {
  return [{json:{ok:false,stage:'campaign',error:$json.error ?? $json}}];
}
return [{json:{ok:true,campaign_id:String($json.id),credential_path:'B'}}];

if (!$json.id) {
  return [{json:{ok:false,stage:'adset',error:$json.error ?? $json}}];
}
return [{json:{ok:true,adset_id:String($json.id),campaign_id:$('Validate Campaign [B]').first().json.campaign_id}}];

const ctx = $('Build Meta Payloads').first().json;
const name = `${ctx.strategy.campaign_name} | Existing Post`;

if (ctx.request.source_platform === 'facebook') {
  if (!ctx.resolved.object_story_id) {
    throw new Error('FACEBOOK_OBJECT_STORY_ID_MISSING');
  }

  return [{
    json: {
      name,
      object_story_id: ctx.resolved.object_story_id
    }
  }];
}

if (!ctx.resolved.instagram_media_id) {
  throw new Error('INSTAGRAM_MEDIA_ID_MISSING');
}

return [{
  json: {
    name,
    source_instagram_media_id: ctx.resolved.instagram_media_id,
    instagram_user_id: ctx.instagram_user_id
  }
}];

if (!$json.id) {
  return [{json:{ok:false,stage:'creative',error:$json.error ?? $json}}];
}
return [{json:{ok:true,creative_id:String($json.id),adset_id:$('Validate Ad Set [B]').first().json.adset_id,campaign_id:$('Validate Ad Set [B]').first().json.campaign_id}}];

if (!$json.id) {
  return [{json:{ok:false,stage:'ad',error:$json.error ?? $json}}];
}
return [{json:{
  ok:true,
  ad_id:String($json.id),
  campaign_id:$('Validate Campaign [B]').first().json.campaign_id,
  adset_id:$('Validate Ad Set [B]').first().json.adset_id,
  creative_id:$('Validate Creative [B]').first().json.creative_id
}}];

if (!$json.id) {
  return [{json:{ok:false,stage:'campaign',error:$json.error ?? $json}}];
}
return [{json:{ok:true,campaign_id:String($json.id),credential_path:'A'}}];

if (!$json.id) {
  return [{json:{ok:false,stage:'adset',error:$json.error ?? $json}}];
}
return [{json:{ok:true,adset_id:String($json.id),campaign_id:$('Validate Campaign [A]').first().json.campaign_id}}];

const ctx = $('Build Meta Payloads').first().json;
const name = `${ctx.strategy.campaign_name} | Existing Post`;

if (ctx.request.source_platform === 'facebook') {
  if (!ctx.resolved.object_story_id) {
    throw new Error('FACEBOOK_OBJECT_STORY_ID_MISSING');
  }

  return [{
    json: {
      name,
      object_story_id: ctx.resolved.object_story_id
    }
  }];
}

if (!ctx.resolved.instagram_media_id) {
  throw new Error('INSTAGRAM_MEDIA_ID_MISSING');
}

return [{
  json: {
    name,
    source_instagram_media_id: ctx.resolved.instagram_media_id,
    instagram_user_id: ctx.instagram_user_id
  }
}];

if (!$json.id) {
  return [{json:{ok:false,stage:'creative',error:$json.error ?? $json}}];
}
return [{json:{ok:true,creative_id:String($json.id),adset_id:$('Validate Ad Set [A]').first().json.adset_id,campaign_id:$('Validate Ad Set [A]').first().json.campaign_id}}];

if (!$json.id) {
  return [{json:{ok:false,stage:'ad',error:$json.error ?? $json}}];
}
return [{json:{
  ok:true,
  ad_id:String($json.id),
  campaign_id:$('Validate Campaign [A]').first().json.campaign_id,
  adset_id:$('Validate Ad Set [A]').first().json.adset_id,
  creative_id:$('Validate Creative [A]').first().json.creative_id
}}];

const ctx = $('Build Meta Payloads').first().json;
const now = new Date().toISOString();

let ids = null;
for (const name of ['Validate Ad [A]', 'Validate Ad [B]']) {
  try {
    const value = $(name).first().json;
    if (value?.ad_id) {
      ids = value;
      break;
    }
  } catch {}
}

if (!ids) throw new Error('META_IDS_NOT_FOUND_AFTER_SUCCESS');

const live = ctx.execution_mode === 'live';

return [{
  json: {
    request_id: ctx.request.id,
    patch: {
      status: live ? 'published' : 'ready_for_review',
      error_code: null,
      error_message: null,
      request_payload: {
        ...(ctx.request.request_payload ?? {}),
        build_completed_at: now,
        auto_execution: true,
        build_progress: {
          stage: 'completed',
          updated_at: now
        },
        meta_status: live ? 'ACTIVE' : 'PAUSED',
        meta_ids: {
          campaign_id: ids.campaign_id,
          adset_id: ids.adset_id,
          creative_id: ids.creative_id,
          ad_id: ids.ad_id
        }
      }
    }
  }
}];

const ctx = $('Build Meta Payloads').first().json;
const row = Array.isArray($json)
  ? ($json[0] ?? null)
  : (Array.isArray($json?.data) ? $json.data[0] : $json);

return [{
  json: {
    ok: true,
    request_id: row?.id ?? ctx.request.id,
    status: row?.status ?? (
      ctx.execution_mode === 'live'
        ? 'published'
        : 'ready_for_review'
    ),
    execution_mode: ctx.execution_mode,
    meta_status:
      ctx.execution_mode === 'live'
        ? 'ACTIVE'
        : 'PAUSED',
    selected_tier: ctx.strategy.tier,
    message:
      ctx.execution_mode === 'live'
        ? 'تم إنشاء الحملة وتشغيلها تلقائيًا بنجاح.'
        : 'تم إنشاء الحملة بحالة PAUSED للمراجعة.'
  }
}];

const data = $json ?? {};
const ctx = $('Select Autonomous Strategy').first().json;

const rawMessage =
  data.error?.message ??
  data.errorMessage ??
  data.message ??
  data.error ??
  data;

const message =
  typeof rawMessage === 'string'
    ? rawMessage
    : JSON.stringify(rawMessage);

const stage = String(data.stage ?? 'validation');

return [{
  json: {
    request_id: ctx.request?.id ?? null,
    strategy_id: ctx.strategy?.id ?? null,
    stage,
    error_code:
      `META_BUILD_${stage.toUpperCase()}_FAILED`,
    error_message: message.slice(0, 2000)
  }
}];

return [{
  json: {
    ok: false,
    http_status: $json.http_status ?? 400,
    error_code:
      $json.error?.code ??
      'BUILD_REQUEST_FAILED',
    error_message:
      $json.error?.message ??
      'تعذر قبول طلب بناء الحملة.'
  }
}];
